package com.example.moviesapp_latiris;

import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.graphics.Color;
import android.os.Bundle;
import android.util.Log;
import android.widget.Button;
import android.widget.ImageView;
import android.widget.RatingBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.app.ActivityCompat;

import com.android.volley.Request;
import com.android.volley.RequestQueue;
import com.android.volley.toolbox.JsonObjectRequest;
import com.android.volley.toolbox.Volley;
import com.bumptech.glide.Glide;
import com.google.android.gms.maps.CameraUpdateFactory;
import com.google.android.gms.maps.GoogleMap;
import com.google.android.gms.maps.OnMapReadyCallback;
import com.google.android.gms.maps.SupportMapFragment;
import com.google.android.gms.maps.model.BitmapDescriptor;
import com.google.android.gms.maps.model.BitmapDescriptorFactory;
import com.google.android.gms.maps.model.LatLng;
import com.google.android.gms.maps.model.MarkerOptions;
import com.google.android.material.bottomnavigation.BottomNavigationView;

import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

public class MovieDetailActivity extends AppCompatActivity implements OnMapReadyCallback {

    private static final String TAG = "MovieDetailActivity";
    private static final String TMDB_API_KEY = "YOUR_API_KEY";
    private static final String TMDB_BASE_URL = "https://api.themoviedb.org/3/movie/";
    private static final String IMAGE_BASE_URL = "https://image.tmdb.org/t/p/w500";

    private static final int LOCATION_PERMISSION_REQUEST_CODE = 1001;

    private final LatLng casablancaLocation = new LatLng(33.5731, -7.5898);

    private TextView movieNameTextView;
    private TextView movieDescriptionTextView;
    private ImageView moviePosterImageView;
    private RatingBar movieDetailRating;
    private TextView movieDetailRatingScore;

    private Button playButton;
    private Button favoriteButton;

    private GoogleMap mMap;

    private RequestQueue requestQueue;

    private String trailerKey = "";
    private String posterPath = "";
    private String releaseDate = "";
    private String movieName = "";
    private double movieRating = 0.0;

    private int currentMovieId = -1;

    private FavoritesManager favoritesManager;
    private boolean isFavorite = false;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_movie_detail);

        favoritesManager = new FavoritesManager();

        initViews();

        requestQueue = Volley.newRequestQueue(this);

        int movieId = getIntent().getIntExtra("movieId", -1);

        if (movieId != -1) {
            currentMovieId = movieId;
            fetchMovieDetails(movieId);
        } else {
            movieDescriptionTextView.setText(R.string.no_movie_id);
        }

        initMap();
        initBottomNavigation();
    }

    private void initViews() {

        movieNameTextView = findViewById(R.id.textName);
        movieDescriptionTextView = findViewById(R.id.Details);
        moviePosterImageView = findViewById(R.id.imageview);
        movieDetailRating = findViewById(R.id.movieDetailRating);
        movieDetailRatingScore = findViewById(R.id.movieDetailRatingScore);

        playButton = findViewById(R.id.playButton);
        favoriteButton = findViewById(R.id.favoriteButton);

        playButton.setOnClickListener(v -> playTrailer());

        favoriteButton.setOnClickListener(v -> toggleFavorite());
    }

    private void initMap() {

        SupportMapFragment mapFragment =
                (SupportMapFragment) getSupportFragmentManager()
                        .findFragmentById(R.id.map);

        if (mapFragment != null) {
            mapFragment.getMapAsync(this);
        }
    }

    private void initBottomNavigation() {

        BottomNavigationView bottomNavigationView =
                findViewById(R.id.bottomNavigation);

        bottomNavigationView.setSelectedItemId(R.id.nav_movies);

        bottomNavigationView.setOnItemSelectedListener(item -> {

            int id = item.getItemId();

            if (id == R.id.nav_home) {

                startActivity(new Intent(this, MainActivity.class));

                return true;

            } else if (id == R.id.nav_explore) {

                startActivity(new Intent(this, MapActivity.class));

                return true;

            } else if (id == R.id.nav_movies) {

                startActivity(new Intent(this, MoviesActivity.class));

                return true;

            } else if (id == R.id.nav_favoris) {

                startActivity(new Intent(this, FavorisActivity.class));

                return true;

            } else if (id == R.id.nav_profile) {

                startActivity(new Intent(this, ProfileActivity.class));

                return true;
            }

            return false;
        });
    }

    private void fetchMovieDetails(int movieId) {

        String detailsUrl =
                TMDB_BASE_URL + movieId + "?api_key=" + TMDB_API_KEY;

        String videosUrl =
                TMDB_BASE_URL + movieId + "/videos?api_key=" + TMDB_API_KEY;

        JsonObjectRequest detailsRequest =
                new JsonObjectRequest(
                        Request.Method.GET,
                        detailsUrl,
                        null,
                        this::handleMovieDetailsResponse,
                        error -> {

                            Log.e(TAG,
                                    "Error fetching movie details: "
                                            + error.getMessage());

                            movieDescriptionTextView.setText(
                                    R.string.failed_to_fetch_details
                            );
                        });

        JsonObjectRequest videosRequest =
                new JsonObjectRequest(
                        Request.Method.GET,
                        videosUrl,
                        null,
                        this::handleMovieVideosResponse,
                        error -> Log.e(TAG,
                                "Error fetching movie videos: "
                                        + error.getMessage())
                );

        requestQueue.add(detailsRequest);
        requestQueue.add(videosRequest);
    }

    private void handleMovieDetailsResponse(JSONObject response) {

        try {

            movieName = response.optString("title", "Unknown");

            posterPath = response.optString("poster_path", "");

            releaseDate = response.optString("release_date", "Unknown");

            movieRating = response.optDouble("vote_average", 0.0);

            String overview =
                    response.optString("overview", "No description");

            movieNameTextView.setText(movieName);

            movieDescriptionTextView.setText(overview);

            // Set rating
            float ratingValue = (float) (movieRating / 2.0); // Convert from 10-point to 5-point scale
            movieDetailRating.setRating(Math.min(5, ratingValue));
            movieDetailRatingScore.setText(String.format("%.1f/10", movieRating));

            Glide.with(this)
                    .load(IMAGE_BASE_URL + posterPath)
                    .into(moviePosterImageView);

            checkAndUpdateFavoriteButton();

        } catch (Exception e) {

            Log.e(TAG,
                    "Error parsing movie details: "
                            + e.getMessage());
        }
    }

    private void handleMovieVideosResponse(JSONObject response) {

        try {

            if (!response.has("results")) return;

            JSONArray results = response.getJSONArray("results");

            for (int i = 0; i < results.length(); i++) {

                JSONObject video = results.getJSONObject(i);

                if ("Trailer".equals(video.getString("type"))) {

                    trailerKey = video.getString("key");

                    break;
                }
            }

        } catch (JSONException e) {

            Log.e(TAG,
                    "Error parsing movie videos: "
                            + e.getMessage());
        }
    }

    private void playTrailer() {

        if (trailerKey != null && !trailerKey.isEmpty()) {

            Intent intent = new Intent(this, VideoPlayer.class);

            intent.putExtra(
                    "videoUrl",
                    "https://www.youtube.com/embed/" + trailerKey
            );

            startActivity(intent);

        } else {

            Toast.makeText(
                    this,
                    R.string.error_trailer_unavailable,
                    Toast.LENGTH_SHORT
            ).show();
        }
    }

    @Override
    public void onMapReady(@NonNull GoogleMap googleMap) {

        mMap = googleMap;

        mMap.moveCamera(
                CameraUpdateFactory.newLatLngZoom(
                        casablancaLocation,
                        12f
                )
        );

        showCasablancaCinemas();

        requestLocationPermission();
    }

    private void showCasablancaCinemas() {

        if (mMap == null) return;

        mMap.clear();

        addCinemaMarker(
                "Megarama Casablanca",
                33.5951,
                -7.6669,
                "Corniche, Casablanca"
        );

        addCinemaMarker(
                "IMAX Morocco Mall",
                33.5786,
                -7.7056,
                "Morocco Mall, Casablanca"
        );

        addCinemaMarker(
                "Cinema Rialto",
                33.5916,
                -7.6158,
                "Rue Mohammed El Qori"
        );
    }

    private void addCinemaMarker(
            String name,
            double lat,
            double lng,
            String snippet
    ) {

        BitmapDescriptor cinemaIcon =
                BitmapDescriptorFactory.fromResource(
                        R.drawable.ic_cinema
                );

        LatLng position = new LatLng(lat, lng);

        mMap.addMarker(
                new MarkerOptions()
                        .position(position)
                        .title(name)
                        .snippet(snippet)
                        .icon(cinemaIcon)
        );
    }

    private void requestLocationPermission() {

        if (ActivityCompat.checkSelfPermission(
                this,
                Manifest.permission.ACCESS_FINE_LOCATION
        ) != PackageManager.PERMISSION_GRANTED) {

            ActivityCompat.requestPermissions(
                    this,
                    new String[]{
                            Manifest.permission.ACCESS_FINE_LOCATION
                    },
                    LOCATION_PERMISSION_REQUEST_CODE
            );

            return;
        }

        mMap.setMyLocationEnabled(true);
    }

    @Override
    public void onRequestPermissionsResult(
            int requestCode,
            @NonNull String[] permissions,
            @NonNull int[] grantResults
    ) {

        super.onRequestPermissionsResult(
                requestCode,
                permissions,
                grantResults
        );

        if (requestCode == LOCATION_PERMISSION_REQUEST_CODE) {

            if (grantResults.length > 0
                    && grantResults[0]
                    == PackageManager.PERMISSION_GRANTED) {

                if (ActivityCompat.checkSelfPermission(
                        this,
                        Manifest.permission.ACCESS_FINE_LOCATION
                ) == PackageManager.PERMISSION_GRANTED) {

                    mMap.setMyLocationEnabled(true);
                }
            }
        }
    }

    private void checkAndUpdateFavoriteButton() {

        if (currentMovieId == -1) return;

        favoritesManager.isFavorite(currentMovieId, isFav -> {

            isFavorite = isFav;

            updateFavoriteButtonUI();
        });
    }

    private void updateFavoriteButtonUI() {

        if (isFavorite) {

            favoriteButton.setText("★ Remove from Favorites");

            favoriteButton.setBackgroundColor(
                    Color.parseColor("#FFC107")
            );

            favoriteButton.setTextColor(Color.BLACK);

        } else {

            favoriteButton.setText("☆ Add to Favorites");

            favoriteButton.setBackgroundColor(
                    Color.parseColor("#666666")
            );

            favoriteButton.setTextColor(Color.WHITE);
        }
    }

    private void toggleFavorite() {

        if (currentMovieId == -1) {

            Toast.makeText(
                    this,
                    "Movie information not available",
                    Toast.LENGTH_SHORT
            ).show();

            return;
        }

        String movieDate = releaseDate;
        String movieImage = posterPath;

        if (isFavorite) {

            favoritesManager.removeFromFavorites(
                    currentMovieId,
                    new FavoritesManager.FavoriteCallback() {

                        @Override
                        public void onSuccess(String message) {

                            isFavorite = false;

                            updateFavoriteButtonUI();

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    message,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }

                        @Override
                        public void onError(String error) {

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    error,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }
                    });

        } else {

            favoritesManager.addToFavorites(
                    currentMovieId,
                    movieName,
                    movieDate,
                    movieImage,
                    movieRating,
                    new FavoritesManager.FavoriteCallback() {

                        @Override
                        public void onSuccess(String message) {

                            isFavorite = true;

                            updateFavoriteButtonUI();

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    message,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }

                        @Override
                        public void onError(String error) {

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    error,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }
                    });
        }
    }
}

package com.example.moviesapp_latiris;

import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.graphics.Color;
import android.os.Bundle;
import android.util.Log;
import android.widget.Button;
import android.widget.ImageView;
import android.widget.RatingBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.app.ActivityCompat;

import com.android.volley.Request;
import com.android.volley.RequestQueue;
import com.android.volley.toolbox.JsonObjectRequest;
import com.android.volley.toolbox.Volley;
import com.bumptech.glide.Glide;
import com.google.android.gms.maps.CameraUpdateFactory;
import com.google.android.gms.maps.GoogleMap;
import com.google.android.gms.maps.OnMapReadyCallback;
import com.google.android.gms.maps.SupportMapFragment;
import com.google.android.gms.maps.model.BitmapDescriptor;
import com.google.android.gms.maps.model.BitmapDescriptorFactory;
import com.google.android.gms.maps.model.LatLng;
import com.google.android.gms.maps.model.MarkerOptions;
import com.google.android.material.bottomnavigation.BottomNavigationView;

import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;

public class MovieDetailActivity extends AppCompatActivity implements OnMapReadyCallback {

    private static final String TAG = "MovieDetailActivity";
    private static final String TMDB_API_KEY = "e21c9bd08ef733416fa4adc42dad2a14";
    private static final String TMDB_BASE_URL = "https://api.themoviedb.org/3/movie/";
    private static final String IMAGE_BASE_URL = "https://image.tmdb.org/t/p/w500";

    private static final int LOCATION_PERMISSION_REQUEST_CODE = 1001;

    private final LatLng casablancaLocation = new LatLng(33.5731, -7.5898);

    private TextView movieNameTextView;
    private TextView movieDescriptionTextView;
    private ImageView moviePosterImageView;
    private RatingBar movieDetailRating;
    private TextView movieDetailRatingScore;

    private Button playButton;
    private Button favoriteButton;

    private GoogleMap mMap;

    private RequestQueue requestQueue;

    private String trailerKey = "";
    private String posterPath = "";
    private String releaseDate = "";
    private String movieName = "";
    private double movieRating = 0.0;

    private int currentMovieId = -1;

    private FavoritesManager favoritesManager;
    private boolean isFavorite = false;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_movie_detail);

        favoritesManager = new FavoritesManager();

        initViews();

        requestQueue = Volley.newRequestQueue(this);

        int movieId = getIntent().getIntExtra("movieId", -1);
        String movieNameExtra = getIntent().getStringExtra("movieName");
        String movieDateExtra = getIntent().getStringExtra("movieDate");
        String movieImageExtra = getIntent().getStringExtra("movieImage");
        double movieRatingExtra = getIntent().getDoubleExtra("movieRating", 0.0);

        if (movieNameExtra != null && !movieNameExtra.isEmpty()) {
            movieName = movieNameExtra;
            movieNameTextView.setText(movieNameExtra);
        }
        if (movieDateExtra != null && !movieDateExtra.isEmpty()) {
            releaseDate = movieDateExtra;
        }
        if (movieImageExtra != null && !movieImageExtra.isEmpty()) {
            posterPath = movieImageExtra;
            Glide.with(this)
                    .load(IMAGE_BASE_URL + movieImageExtra)
                    .into(moviePosterImageView);
        }
        if (movieRatingExtra > 0.0) {
            movieRating = movieRatingExtra;
            float ratingValue = (float) (movieRatingExtra / 2.0);
            movieDetailRating.setRating(Math.min(5, ratingValue));
            movieDetailRatingScore.setText(String.format("%.1f/10", movieRatingExtra));
        }

        if (movieId != -1) {
            currentMovieId = movieId;
            fetchMovieDetails(movieId);
        } else {
            movieDescriptionTextView.setText(R.string.no_movie_id);
        }

        initMap();
        initBottomNavigation();
    }

    private void initViews() {

        movieNameTextView = findViewById(R.id.textName);
        movieDescriptionTextView = findViewById(R.id.Details);
        moviePosterImageView = findViewById(R.id.imageview);
        movieDetailRating = findViewById(R.id.movieDetailRating);
        movieDetailRatingScore = findViewById(R.id.movieDetailRatingScore);

        playButton = findViewById(R.id.playButton);
        favoriteButton = findViewById(R.id.favoriteButton);

        playButton.setOnClickListener(v -> playTrailer());

        favoriteButton.setOnClickListener(v -> toggleFavorite());
    }

    private void initMap() {

        SupportMapFragment mapFragment =
                (SupportMapFragment) getSupportFragmentManager()
                        .findFragmentById(R.id.map);

        if (mapFragment != null) {
            mapFragment.getMapAsync(this);
        }
    }

    private void initBottomNavigation() {

        BottomNavigationView bottomNavigationView =
                findViewById(R.id.bottomNavigation);

        bottomNavigationView.setSelectedItemId(R.id.nav_movies);

        bottomNavigationView.setOnItemSelectedListener(item -> {

            int id = item.getItemId();

            if (id == R.id.nav_home) {

                startActivity(new Intent(this, MainActivity.class));

                return true;

            } else if (id == R.id.nav_explore) {

                startActivity(new Intent(this, MapActivity.class));

                return true;

            } else if (id == R.id.nav_movies) {

                startActivity(new Intent(this, MoviesActivity.class));

                return true;

            } else if (id == R.id.nav_favoris) {

                startActivity(new Intent(this, FavorisActivity.class));

                return true;

            } else if (id == R.id.nav_profile) {

                startActivity(new Intent(this, ProfileActivity.class));

                return true;
            }

            return false;
        });
    }

    private void fetchMovieDetails(int movieId) {

        String detailsUrl =
                TMDB_BASE_URL + movieId + "?api_key=" + TMDB_API_KEY;

        String videosUrl =
                TMDB_BASE_URL + movieId + "/videos?api_key=" + TMDB_API_KEY;

        JsonObjectRequest detailsRequest =
                new JsonObjectRequest(
                        Request.Method.GET,
                        detailsUrl,
                        null,
                        this::handleMovieDetailsResponse,
                        error -> {

                            Log.e(TAG,
                                    "Error fetching movie details: "
                                            + error.getMessage());

                            movieDescriptionTextView.setText(
                                    R.string.failed_to_fetch_details
                            );
                        });

        JsonObjectRequest videosRequest =
                new JsonObjectRequest(
                        Request.Method.GET,
                        videosUrl,
                        null,
                        this::handleMovieVideosResponse,
                        error -> Log.e(TAG,
                                "Error fetching movie videos: "
                                        + error.getMessage())
                );

        requestQueue.add(detailsRequest);
        requestQueue.add(videosRequest);
    }

    private void handleMovieDetailsResponse(JSONObject response) {

        try {

            movieName = response.optString("title", "Unknown");

            posterPath = response.optString("poster_path", "");

            releaseDate = response.optString("release_date", "Unknown");

            movieRating = response.optDouble("vote_average", 0.0);

            String overview =
                    response.optString("overview", "No description");

            movieNameTextView.setText(movieName);

            movieDescriptionTextView.setText(overview);

            // Set rating
            float ratingValue = (float) (movieRating / 2.0); // Convert from 10-point to 5-point scale
            movieDetailRating.setRating(Math.min(5, ratingValue));
            movieDetailRatingScore.setText(String.format("%.1f/10", movieRating));

            Glide.with(this)
                    .load(IMAGE_BASE_URL + posterPath)
                    .into(moviePosterImageView);

            checkAndUpdateFavoriteButton();

        } catch (Exception e) {

            Log.e(TAG,
                    "Error parsing movie details: "
                            + e.getMessage());
        }
    }

    private void handleMovieVideosResponse(JSONObject response) {

        try {

            if (!response.has("results")) return;

            JSONArray results = response.getJSONArray("results");

            for (int i = 0; i < results.length(); i++) {

                JSONObject video = results.getJSONObject(i);

                if ("Trailer".equals(video.getString("type"))) {

                    trailerKey = video.getString("key");

                    break;
                }
            }

        } catch (JSONException e) {

            Log.e(TAG,
                    "Error parsing movie videos: "
                            + e.getMessage());
        }
    }

    private void playTrailer() {

        if (trailerKey != null && !trailerKey.isEmpty()) {

            Intent intent = new Intent(this, VideoPlayer.class);

            intent.putExtra(
                    "videoUrl",
                    "https://www.youtube.com/embed/" + trailerKey
            );

            startActivity(intent);

        } else {

            Toast.makeText(
                    this,
                    R.string.error_trailer_unavailable,
                    Toast.LENGTH_SHORT
            ).show();
        }
    }

    @Override
    public void onMapReady(@NonNull GoogleMap googleMap) {

        mMap = googleMap;

        mMap.moveCamera(
                CameraUpdateFactory.newLatLngZoom(
                        casablancaLocation,
                        12f
                )
        );

        showCasablancaCinemas();

        requestLocationPermission();
    }

    private void showCasablancaCinemas() {

        if (mMap == null) return;

        mMap.clear();

        addCinemaMarker(
                "Megarama Casablanca",
                33.5951,
                -7.6669,
                "Corniche, Casablanca"
        );

        addCinemaMarker(
                "IMAX Morocco Mall",
                33.5786,
                -7.7056,
                "Morocco Mall, Casablanca"
        );

        addCinemaMarker(
                "Cinema Rialto",
                33.5916,
                -7.6158,
                "Rue Mohammed El Qori"
        );
    }

    private void addCinemaMarker(
            String name,
            double lat,
            double lng,
            String snippet
    ) {

        BitmapDescriptor cinemaIcon =
                BitmapDescriptorFactory.fromResource(
                        R.drawable.ic_cinema
                );

        LatLng position = new LatLng(lat, lng);

        mMap.addMarker(
                new MarkerOptions()
                        .position(position)
                        .title(name)
                        .snippet(snippet)
                        .icon(cinemaIcon)
        );
    }

    private void requestLocationPermission() {

        if (ActivityCompat.checkSelfPermission(
                this,
                Manifest.permission.ACCESS_FINE_LOCATION
        ) != PackageManager.PERMISSION_GRANTED) {

            ActivityCompat.requestPermissions(
                    this,
                    new String[]{
                            Manifest.permission.ACCESS_FINE_LOCATION
                    },
                    LOCATION_PERMISSION_REQUEST_CODE
            );

            return;
        }

        mMap.setMyLocationEnabled(true);
    }

    @Override
    public void onRequestPermissionsResult(
            int requestCode,
            @NonNull String[] permissions,
            @NonNull int[] grantResults
    ) {

        super.onRequestPermissionsResult(
                requestCode,
                permissions,
                grantResults
        );

        if (requestCode == LOCATION_PERMISSION_REQUEST_CODE) {

            if (grantResults.length > 0
                    && grantResults[0]
                    == PackageManager.PERMISSION_GRANTED) {

                if (ActivityCompat.checkSelfPermission(
                        this,
                        Manifest.permission.ACCESS_FINE_LOCATION
                ) == PackageManager.PERMISSION_GRANTED) {

                    mMap.setMyLocationEnabled(true);
                }
            }
        }
    }

    private void checkAndUpdateFavoriteButton() {

        if (currentMovieId == -1) return;

        favoritesManager.isFavorite(currentMovieId, isFav -> {

            isFavorite = isFav;

            updateFavoriteButtonUI();
        });
    }

    private void updateFavoriteButtonUI() {

        if (isFavorite) {

            favoriteButton.setText("★ Remove from Favorites");

            favoriteButton.setBackgroundColor(
                    Color.parseColor("#FFC107")
            );

            favoriteButton.setTextColor(Color.BLACK);

        } else {

            favoriteButton.setText("☆ Add to Favorites");

            favoriteButton.setBackgroundColor(
                    Color.parseColor("#666666")
            );

            favoriteButton.setTextColor(Color.WHITE);
        }
    }

    private void toggleFavorite() {

        if (currentMovieId == -1) {

            Toast.makeText(
                    this,
                    "Movie information not available",
                    Toast.LENGTH_SHORT
            ).show();

            return;
        }

        String movieDate = releaseDate;
        String movieImage = posterPath;

        if (isFavorite) {

            favoritesManager.removeFromFavorites(
                    currentMovieId,
                    new FavoritesManager.FavoriteCallback() {

                        @Override
                        public void onSuccess(String message) {

                            isFavorite = false;

                            updateFavoriteButtonUI();

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    message,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }

                        @Override
                        public void onError(String error) {

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    error,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }
                    });

        } else {

            favoritesManager.addToFavorites(
                    currentMovieId,
                    movieName,
                    movieDate,
                    movieImage,
                    movieRating,
                    new FavoritesManager.FavoriteCallback() {

                        @Override
                        public void onSuccess(String message) {

                            isFavorite = true;

                            updateFavoriteButtonUI();

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    message,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }

                        @Override
                        public void onError(String error) {

                            Toast.makeText(
                                    MovieDetailActivity.this,
                                    error,
                                    Toast.LENGTH_SHORT
                            ).show();
                        }
                    });
        }
    }
}

package com.example.moviesapp_latiris;

import android.content.Intent;
import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.util.Log;
import android.view.inputmethod.EditorInfo;
import android.widget.EditText;
import android.widget.ImageView;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.android.volley.Request;
import com.android.volley.RequestQueue;
import com.android.volley.toolbox.JsonObjectRequest;
import com.android.volley.toolbox.Volley;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;
import java.util.ArrayList;
import java.util.List;

public class MoviesActivity extends AppCompatActivity {
    private static final String TAG = "MoviesActivity";
    private static final String TMDB_API_KEY = "e21c9bd08ef733416fa4adc42dad2a14";
    private static final String BASE_URL = "https://api.themoviedb.org/3";

    private RecyclerView moviesRecyclerView;
    private RecyclerView genreRecyclerView;
    private EditText searchEditText;
    private ImageView searchButton;
    private MyMovieAdapter movieAdapter;
    private GenreAdapter genreAdapter;
    private RequestQueue requestQueue;

    private List<GenreData> genreList = new ArrayList<>();
    private int selectedGenreId = -1;

    // Pagination variables
    private int currentPage = 1;
    private boolean isLoading = false;
    private String currentQuery = null;

    // Search debounce
    private static final long SEARCH_DELAY_MS = 500; // Délai avant de faire la recherche
    private Runnable searchRunnable;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_movies);

        initViews();
        requestQueue = Volley.newRequestQueue(this);

        setupMoviesRecyclerView();
        setupGenreRecyclerView();

        fetchGenres();
        fetchMovies(null, -1, 1); // Initial load: popular movies

        initBottomNavigation();
    }

    private void initViews() {
        moviesRecyclerView = findViewById(R.id.moviesRecyclerView);
        genreRecyclerView = findViewById(R.id.genreRecyclerView);
        searchEditText = findViewById(R.id.searchEditText);
        searchButton = findViewById(R.id.searchButton);

        // Add TextWatcher for real-time search
        searchEditText.addTextChangedListener(new TextWatcher() {
            @Override
            public void beforeTextChanged(CharSequence s, int start, int count, int after) {
                // No action needed
            }

            @Override
            public void onTextChanged(CharSequence s, int start, int before, int count) {
                // Remove previous callback
                searchEditText.removeCallbacks(searchRunnable);

                // Create new search runnable with debounce
                searchRunnable = () -> performSearch();
                searchEditText.postDelayed(searchRunnable, SEARCH_DELAY_MS);
            }

            @Override
            public void afterTextChanged(Editable s) {
                // No action needed
            }
        });

        // Keep the search button for manual search
        searchButton.setOnClickListener(v -> {
            searchEditText.removeCallbacks(searchRunnable);
            performSearch();
        });

        searchEditText.setOnEditorActionListener((v, actionId, event) -> {
            if (actionId == EditorInfo.IME_ACTION_SEARCH) {
                searchEditText.removeCallbacks(searchRunnable);
                performSearch();
                return true;
            }
            return false;
        });
    }

    private void setupMoviesRecyclerView() {
        GridLayoutManager layoutManager = new GridLayoutManager(this, 2);
        moviesRecyclerView.setLayoutManager(layoutManager);
        movieAdapter = new MyMovieAdapter(new ArrayList<>(), this);
        moviesRecyclerView.setAdapter(movieAdapter);

        // Add scroll listener for pagination
        moviesRecyclerView.addOnScrollListener(new RecyclerView.OnScrollListener() {
            @Override
            public void onScrolled(@NonNull RecyclerView recyclerView, int dx, int dy) {
                super.onScrolled(recyclerView, dx, dy);

                int visibleItemCount = layoutManager.getChildCount();
                int totalItemCount = layoutManager.getItemCount();
                int firstVisibleItemPosition = layoutManager.findFirstVisibleItemPosition();

                if (!isLoading) {
                    if ((visibleItemCount + firstVisibleItemPosition) >= totalItemCount
                            && firstVisibleItemPosition >= 0) {
                        loadMoreMovies();
                    }
                }
            }
        });
    }

    private void setupGenreRecyclerView() {
        genreRecyclerView.setLayoutManager(new LinearLayoutManager(this, LinearLayoutManager.HORIZONTAL, false));
        genreAdapter = new GenreAdapter(genreList, genre -> {
            selectedGenreId = genre.getId();
            currentQuery = null;
            currentPage = 1;
            fetchMovies(null, selectedGenreId, currentPage);
        });
        genreRecyclerView.setAdapter(genreAdapter);
    }

    private void performSearch() {
        String query = searchEditText.getText().toString().trim();
        if (!query.isEmpty()) {
            currentQuery = query;
            selectedGenreId = -1;
            currentPage = 1;
            fetchMovies(query, -1, currentPage);
            // Reset genre selection
            for (GenreData g : genreList) g.setSelected(false);
            genreAdapter.notifyDataSetChanged();
        }
    }

    private void loadMoreMovies() {
        currentPage++;
        fetchMovies(currentQuery, selectedGenreId, currentPage);
    }

    private void fetchGenres() {
        String url = BASE_URL + "/genre/movie/list?api_key=" + TMDB_API_KEY;
        JsonObjectRequest request = new JsonObjectRequest(Request.Method.GET, url, null,
                response -> {
                    try {
                        JSONArray genres = response.getJSONArray("genres");
                        genreList.clear();
                        genreList.add(new GenreData(-1, "All")); // Default option
                        genreList.get(0).setSelected(true);

                        for (int i = 0; i < genres.length(); i++) {
                            JSONObject obj = genres.getJSONObject(i);
                            genreList.add(new GenreData(obj.getInt("id"), obj.getString("name")));
                        }
                        genreAdapter.notifyDataSetChanged();
                    } catch (JSONException e) {
                        Log.e(TAG, "Genre parse error", e);
                    }
                }, error -> Log.e(TAG, "Genre fetch error", error));
        requestQueue.add(request);
    }

    private void fetchMovies(String query, int genreId, int page) {
        isLoading = true;
        String url;
        if (query != null && !query.isEmpty()) {
            url = BASE_URL + "/search/movie?api_key=" + TMDB_API_KEY + "&query=" + query + "&page=" + page;
        } else if (genreId != -1) {
            url = BASE_URL + "/discover/movie?api_key=" + TMDB_API_KEY + "&with_genres=" + genreId + "&page=" + page;
        } else {
            url = BASE_URL + "/movie/popular?api_key=" + TMDB_API_KEY + "&page=" + page;
        }

        JsonObjectRequest request = new JsonObjectRequest(Request.Method.GET, url, null,
                response -> {
                    try {
                        JSONArray results = response.getJSONArray("results");
                        List<MyMovieData> movies = new ArrayList<>();
                        for (int i = 0; i < results.length(); i++) {
                            JSONObject obj = results.getJSONObject(i);
                            movies.add(new MyMovieData(
                                    obj.getInt("id"),
                                    obj.getString("title"),
                                    obj.optString("release_date", "N/A"),
                                    obj.optString("poster_path", ""),
                                    obj.optDouble("vote_average", 0.0)
                            ));
                        }

                        if (page == 1) {
                            movieAdapter.setMovies(movies);
                        } else {
                            movieAdapter.addMovies(movies);
                        }
                    } catch (JSONException e) {
                        Log.e(TAG, "Movie parse error", e);
                    } finally {
                        isLoading = false;
                    }
                }, error -> {
                    Log.e(TAG, "Movie fetch error", error);
                    isLoading = false;
                });
        requestQueue.add(request);
    }

    private void initBottomNavigation() {
        BottomNavigationView bottomNavigationView = findViewById(R.id.bottomNavigation);
        BottomNavHelper.setupBottomNavigation(this, bottomNavigationView, R.id.nav_movies);
    }

    @Override
    protected void onResume() {
        super.onResume();
        BottomNavigationView bottomNav = findViewById(R.id.bottomNavigation);
        if (bottomNav != null) {
            BottomNavHelper.updateSelectedItem(bottomNav, R.id.nav_movies);
        }
    }
}

package com.example.moviesapp_latiris;

import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.os.Bundle;
import android.speech.RecognizerIntent;
import android.text.Editable;
import android.text.TextWatcher;
import android.util.Log;
import android.view.inputmethod.EditorInfo;
import android.widget.EditText;
import android.widget.ImageView;
import android.widget.Toast;
import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;
import androidx.recyclerview.widget.GridLayoutManager;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.android.volley.Request;
import com.android.volley.RequestQueue;
import com.android.volley.toolbox.JsonObjectRequest;
import com.android.volley.toolbox.Volley;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import org.json.JSONArray;
import org.json.JSONException;
import org.json.JSONObject;
import java.util.ArrayList;
import java.util.List;

public class MoviesActivity extends AppCompatActivity {
    private static final String TAG = "MoviesActivity";
    private static final String TMDB_API_KEY = "e21c9bd08ef733416fa4adc42dad2a14";
    private static final String BASE_URL = "https://api.themoviedb.org/3";

    private RecyclerView moviesRecyclerView;
    private RecyclerView genreRecyclerView;
    private EditText searchEditText;
    private ImageView searchButton;
    private ImageView voiceSearchButton;
    private MyMovieAdapter movieAdapter;
    private GenreAdapter genreAdapter;
    private RequestQueue requestQueue;

    private ActivityResultLauncher<String> audioPermissionLauncher;
    private ActivityResultLauncher<Intent> voiceSearchLauncher;

    private List<GenreData> genreList = new ArrayList<>();
    private int selectedGenreId = -1;

    // Pagination variables
    private int currentPage = 1;
    private boolean isLoading = false;
    private String currentQuery = null;

    // Search debounce
    private static final long SEARCH_DELAY_MS = 500; // Délai avant de faire la recherche
    private Runnable searchRunnable;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_movies);

        initViews();
        initVoiceSearch();
        requestQueue = Volley.newRequestQueue(this);

        setupMoviesRecyclerView();
        setupGenreRecyclerView();

        fetchGenres();
        fetchMovies(null, -1, 1); // Initial load: popular movies

        initBottomNavigation();
    }

    private void initViews() {
        moviesRecyclerView = findViewById(R.id.moviesRecyclerView);
        genreRecyclerView = findViewById(R.id.genreRecyclerView);
        searchEditText = findViewById(R.id.searchEditText);
        searchButton = findViewById(R.id.searchButton);
        voiceSearchButton = findViewById(R.id.voiceSearchButton);

        // Add TextWatcher for real-time search
        searchEditText.addTextChangedListener(new TextWatcher() {
            @Override
            public void beforeTextChanged(CharSequence s, int start, int count, int after) {
                // No action needed
            }

            @Override
            public void onTextChanged(CharSequence s, int start, int before, int count) {
                // Remove previous callback
                searchEditText.removeCallbacks(searchRunnable);

                // Create new search runnable with debounce
                searchRunnable = () -> performSearch();
                searchEditText.postDelayed(searchRunnable, SEARCH_DELAY_MS);
            }

            @Override
            public void afterTextChanged(Editable s) {
                // No action needed
            }
        });

        // Keep the search button for manual search
        searchButton.setOnClickListener(v -> {
            searchEditText.removeCallbacks(searchRunnable);
            performSearch();
        });

        voiceSearchButton.setOnClickListener(v -> startVoiceSearch());

        searchEditText.setOnEditorActionListener((v, actionId, event) -> {
            if (actionId == EditorInfo.IME_ACTION_SEARCH) {
                searchEditText.removeCallbacks(searchRunnable);
                performSearch();
                return true;
            }
            return false;
        });
    }

    private void initVoiceSearch() {
        audioPermissionLauncher = registerForActivityResult(
                new ActivityResultContracts.RequestPermission(),
                isGranted -> {
                    if (isGranted) {
                        launchVoiceSearchIntent();
                    } else {
                        Toast.makeText(this, "Microphone permission denied", Toast.LENGTH_SHORT).show();
                    }
                });

        voiceSearchLauncher = registerForActivityResult(
                new ActivityResultContracts.StartActivityForResult(),
                result -> {
                    if (result.getResultCode() == RESULT_OK && result.getData() != null) {
                        ArrayList<String> results = result.getData()
                                .getStringArrayListExtra(RecognizerIntent.EXTRA_RESULTS);
                        if (results != null && !results.isEmpty()) {
                            String spokenQuery = results.get(0).trim();
                            if (!spokenQuery.isEmpty()) {
                                searchEditText.setText(spokenQuery);
                                searchEditText.setSelection(spokenQuery.length());
                                searchEditText.removeCallbacks(searchRunnable);
                                performSearch();
                            }
                        }
                    }
                });
    }

    private void startVoiceSearch() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.RECORD_AUDIO)
                == PackageManager.PERMISSION_GRANTED) {
            launchVoiceSearchIntent();
        } else {
            audioPermissionLauncher.launch(Manifest.permission.RECORD_AUDIO);
        }
    }

    private void launchVoiceSearchIntent() {
        Intent intent = new Intent(RecognizerIntent.ACTION_RECOGNIZE_SPEECH);
        intent.putExtra(RecognizerIntent.EXTRA_LANGUAGE_MODEL, RecognizerIntent.LANGUAGE_MODEL_FREE_FORM);
        intent.putExtra(RecognizerIntent.EXTRA_PROMPT, "Search movies");

        if (intent.resolveActivity(getPackageManager()) != null) {
            voiceSearchLauncher.launch(intent);
        } else {
            Toast.makeText(this, "Voice search not available", Toast.LENGTH_SHORT).show();
        }
    }

    private void setupMoviesRecyclerView() {
        GridLayoutManager layoutManager = new GridLayoutManager(this, 2);
        moviesRecyclerView.setLayoutManager(layoutManager);
        movieAdapter = new MyMovieAdapter(new ArrayList<>(), this);
        moviesRecyclerView.setAdapter(movieAdapter);

        // Add scroll listener for pagination
        moviesRecyclerView.addOnScrollListener(new RecyclerView.OnScrollListener() {
            @Override
            public void onScrolled(@NonNull RecyclerView recyclerView, int dx, int dy) {
                super.onScrolled(recyclerView, dx, dy);

                int visibleItemCount = layoutManager.getChildCount();
                int totalItemCount = layoutManager.getItemCount();
                int firstVisibleItemPosition = layoutManager.findFirstVisibleItemPosition();

                if (!isLoading) {
                    if ((visibleItemCount + firstVisibleItemPosition) >= totalItemCount
                            && firstVisibleItemPosition >= 0) {
                        loadMoreMovies();
                    }
                }
            }
        });
    }

    private void setupGenreRecyclerView() {
        genreRecyclerView.setLayoutManager(new LinearLayoutManager(this, LinearLayoutManager.HORIZONTAL, false));
        genreAdapter = new GenreAdapter(genreList, genre -> {
            selectedGenreId = genre.getId();
            currentQuery = null;
            currentPage = 1;
            fetchMovies(null, selectedGenreId, currentPage);
        });
        genreRecyclerView.setAdapter(genreAdapter);
    }

    private void performSearch() {
        String query = searchEditText.getText().toString().trim();
        if (!query.isEmpty()) {
            currentQuery = query;
            selectedGenreId = -1;
            currentPage = 1;
            fetchMovies(query, -1, currentPage);
            // Reset genre selection
            for (GenreData g : genreList) g.setSelected(false);
            genreAdapter.notifyDataSetChanged();
        }
    }

    private void loadMoreMovies() {
        currentPage++;
        fetchMovies(currentQuery, selectedGenreId, currentPage);
    }

    private void fetchGenres() {
        String url = BASE_URL + "/genre/movie/list?api_key=" + TMDB_API_KEY;
        JsonObjectRequest request = new JsonObjectRequest(Request.Method.GET, url, null,
                response -> {
                    try {
                        JSONArray genres = response.getJSONArray("genres");
                        genreList.clear();
                        genreList.add(new GenreData(-1, "All")); // Default option
                        genreList.get(0).setSelected(true);

                        for (int i = 0; i < genres.length(); i++) {
                            JSONObject obj = genres.getJSONObject(i);
                            genreList.add(new GenreData(obj.getInt("id"), obj.getString("name")));
                        }
                        genreAdapter.notifyDataSetChanged();
                    } catch (JSONException e) {
                        Log.e(TAG, "Genre parse error", e);
                    }
                }, error -> Log.e(TAG, "Genre fetch error", error));
        requestQueue.add(request);
    }

    private void fetchMovies(String query, int genreId, int page) {
        isLoading = true;
        String url;
        if (query != null && !query.isEmpty()) {
            url = BASE_URL + "/search/movie?api_key=" + TMDB_API_KEY + "&query=" + query + "&page=" + page;
        } else if (genreId != -1) {
            url = BASE_URL + "/discover/movie?api_key=" + TMDB_API_KEY + "&with_genres=" + genreId + "&page=" + page;
        } else {
            url = BASE_URL + "/movie/popular?api_key=" + TMDB_API_KEY + "&page=" + page;
        }

        JsonObjectRequest request = new JsonObjectRequest(Request.Method.GET, url, null,
                response -> {
                    try {
                        JSONArray results = response.getJSONArray("results");
                        List<MyMovieData> movies = new ArrayList<>();
                        for (int i = 0; i < results.length(); i++) {
                            JSONObject obj = results.getJSONObject(i);
                            movies.add(new MyMovieData(
                                    obj.getInt("id"),
                                    obj.getString("title"),
                                    obj.optString("release_date", "N/A"),
                                    obj.optString("poster_path", ""),
                                    obj.optDouble("vote_average", 0.0)
                            ));
                        }

                        if (page == 1) {
                            movieAdapter.setMovies(movies);
                        } else {
                            movieAdapter.addMovies(movies);
                        }
                    } catch (JSONException e) {
                        Log.e(TAG, "Movie parse error", e);
                    } finally {
                        isLoading = false;
                    }
                }, error -> {
                    Log.e(TAG, "Movie fetch error", error);
                    isLoading = false;
                });
        requestQueue.add(request);
    }

    private void initBottomNavigation() {
        BottomNavigationView bottomNavigationView = findViewById(R.id.bottomNavigation);
        BottomNavHelper.setupBottomNavigation(this, bottomNavigationView, R.id.nav_movies);
    }

    @Override
    protected void onResume() {
        super.onResume();
        BottomNavigationView bottomNav = findViewById(R.id.bottomNavigation);
        if (bottomNav != null) {
            BottomNavHelper.updateSelectedItem(bottomNav, R.id.nav_movies);
        }
    }
}

package com.example.moviesapp_latiris;

import android.content.Context;
import android.content.Intent;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ImageView;
import android.widget.RatingBar;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;
import com.bumptech.glide.Glide;
import java.util.ArrayList;
import java.util.List;

public class MyMovieAdapter extends RecyclerView.Adapter<MyMovieAdapter.ViewHolder> {
    private List<MyMovieData> myMovieData;
    private Context context;

    public MyMovieAdapter(List<MyMovieData> myMovieData, Context context) {
        this.myMovieData = myMovieData;
        this.context = context;
    }

    public void addMovies(List<MyMovieData> newMovies) {
        int startPos = myMovieData.size();
        myMovieData.addAll(newMovies);
        notifyItemRangeInserted(startPos, newMovies.size());
    }

    public void setMovies(List<MyMovieData> movies) {
        this.myMovieData = new ArrayList<>(movies);
        notifyDataSetChanged();
    }

    @NonNull
    @Override
    public ViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        LayoutInflater layoutInflater = LayoutInflater.from(parent.getContext());
        View view = layoutInflater.inflate(R.layout.movie_item_list, parent, false);
        return new ViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull ViewHolder holder, int position) {
        final MyMovieData movie = myMovieData.get(position);
        holder.textViewName.setText(movie.getMovieName());
        holder.textViewDate.setText(movie.getMovieDate());

        // Set rating
        float ratingValue = (float) (movie.getRating() / 2.0); // Convert from 10-point to 5-point scale
        holder.movieRating.setRating(Math.min(5, ratingValue));
        holder.movieRatingScore.setText(String.format("%.1f", movie.getRating()));

        String imageUrl = "https://image.tmdb.org/t/p/w500" + movie.getMovieImage();

        Glide.with(context)
                .load(imageUrl)
                .into(holder.movieImage);

        holder.itemView.setOnClickListener(v -> {
            Intent intent = new Intent(context, MovieDetailActivity.class);
            intent.putExtra("movieId", movie.getId());
            context.startActivity(intent);
        });
    }

    @Override
    public int getItemCount() {
        return myMovieData.size();
    }

    public class ViewHolder extends RecyclerView.ViewHolder {
        ImageView movieImage;
        TextView textViewName;
        TextView textViewDate;
        RatingBar movieRating;
        TextView movieRatingScore;

        public ViewHolder(@NonNull View itemView) {
            super(itemView);
            movieImage = itemView.findViewById(R.id.moviePoster);
            textViewName = itemView.findViewById(R.id.movieTitle);
            textViewDate = itemView.findViewById(R.id.textdate);
            movieRating = itemView.findViewById(R.id.movieRating);
            movieRatingScore = itemView.findViewById(R.id.movieRatingScore);
        }
    }
}

